  9→];
 10→
 11→function jsxInJsPlugin(): PluginOption {
 12→  return {
 13→    name: 'storybook:jsx-in-js',
 14→    enforce: 'pre',
 15→    async transform(code, id) {
 16→      const cleanId = id.replace(/\?.*$/, '');
 17→      if (
 18→        /\.js$/.test(cleanId) &&
 19→        JSX_JS_PACKAGES.some(pkg => id.includes(pkg)) &&
 20→        (code.includes('<') || code.includes('/>'))
 21→      ) {
 22→        return transformWithEsbuild(code, id, {
 23→          loader: 'jsx',
 24→          jsx: 'automatic',
 25→        });
 26→      }
 27→    },
 28→  };
 29→}
 30→
 31→const CJS_IN_ESM_PACKAGES = [
 32→  'react-native-svg/lib/module/',
 33→  'react-native-reanimated/lib/module/',
 34→];
 35→
 36→function dtsStubPlugin(): PluginOption {
 37→  return {
 38→    name: 'storybook:dts-stub',
 39→    enforce: 'pre',
 40→    resolveId(source, importer) {
 41→      if (!importer?.includes('@semparar/')) return;
 42→      const cleanImporter = importer.replace(/\?.*$/, '');
 43→      const cleanSource = source.replace(/\?.*$/, '');
 44→      const dir = path.dirname(cleanImporter);
 45→
 46→      if (cleanSource.endsWith('.d') || cleanSource.endsWith('.d.ts')) {
 47→        const absPath =
 48→          cleanSource.startsWith('.') || !cleanSource.startsWith('/')
 49→            ? path.resolve(dir, cleanSource)
 50→            : cleanSource;
 51→        const dtsPath = absPath.endsWith('.d.ts')
 52→          ? absPath
 53→          : absPath + '.ts';
 54→        return `\0dts-stub:${dtsPath}`;
 55→      }
 56→
 57→      if (
 58→        cleanImporter.includes('node_modules/@semparar/') &&
 59→        !cleanSource.startsWith('\0') &&
 60→        (cleanSource.startsWith('.') || cleanSource.startsWith('/'))
 61→      ) {
 62→        const candidate = path.resolve(dir, cleanSource);
 63→        const dtsCandidate = candidate + '.d.ts';
 64→        try {
 65→          require('fs').accessSync(dtsCandidate);
 66→          return `\0dts-stub:${dtsCandidate}`;
 67→        } catch {
 68→          // not a .d.ts, let Vite handle it normally
 69→        }
 70→      }
 71→    },
 72→    load(id) {
 73→      if (!id.startsWith('\0dts-stub:')) return;
 74→      const realPath = id.replace('\0dts-stub:', '');
 75→      try {
 76→        const fs = require('fs');
 77→        const filePath = realPath.endsWith('.d.ts')
 78→          ? realPath
 79→          : realPath + '.d.ts';
 80→        const src = fs.readFileSync(filePath, 'utf-8');
 81→        const names = [
 82→          ...src.matchAll(
 83→            /export\s+(?:interface|type|const|function|class|enum)\s+(\w+)/g,
 84→          ),
 85→        ].map(m => m[1]);
 86→        if (names.length) {
 87→          return names
 88→            .map(n => `export const ${n} = {};`)
 89→            .concat(['export default {};'])
 90→            .join('\n');
 91→        }
 92→      } catch {
 93→        // file not readable, fall through to default stub
 94→      }
 95→      return 'export default {};';
 96→    },
 97→  };
 98→}
 99→
100→function circularFixPlugin(): PluginOption {
101→  return {
102→    name: 'storybook:circular-fix',
103→    enforce: 'pre',
104→    resolveId(source, importer) {
105→      if (
106→        importer?.includes('CardOptionDrag/view.tsx') &&
107→        source === './view.group'
108→      ) {
109→        return '\0circular-stub:CardOptionDragGroup';
110→      }
111→    },
112→    load(id) {
113→      if (id === '\0circular-stub:CardOptionDragGroup') {
114→        return 'export default function CardOptionDragGroup() { return null; }';
115→      }
116→    },
117→  };
118→}
119→
120→function cjsToEsmPlugin(): PluginOption {
121→  return {
122→    name: 'storybook:cjs-to-esm',
123→    enforce: 'pre',
124→    transform(code, id) {
125→      const cleanId = id.replace(/\?.*$/, '');
126→      if (
127→        !(/\.js$/.test(cleanId) && code.includes('module.exports')) ||
128→        !CJS_IN_ESM_PACKAGES.some(pkg => cleanId.includes(pkg))
129→      ) {
130→        return;
131→      }
132→
133→      const objMatch = code.match(/module\.exports\s*=\s*\{([^}]+)\}/);
134→      if (objMatch) {
135→        const isIdentifier = /^[a-zA-Z_$][a-zA-Z0-9_$]*$/;
136→        const entries = objMatch[1]
137→          .split(',')
138→          .map(e => e.trim())
139→          .filter(Boolean)
140→          .filter(e => {
141→            const parts = e.split(':').map(p => p.trim());
142→            return parts.every(p => isIdentifier.test(p));
143→          })
144→          .map(e => {
145→            const parts = e.split(':').map(p => p.trim());
146→            if (parts.length === 2 && parts[0] !== parts[1]) {
147→              return `export { ${parts[1]} as ${parts[0]} };`;
148→            }
149→            return `export { ${parts[0]} };`;
150→          });
151→        const exportsBlock = entries.join('\n');
152→        return code
153→          .replace(/["']use strict["'];?\s*/, '')
154→          .replace(/module\.exports\s*=\s*\{[^}]+\};?/, exportsBlock);
155→      }
156→
157→      const simpleMatch = code.match(
158→        /module\.exports\s*=\s*([a-zA-Z_$][a-zA-Z0-9_$]*|null|undefined|\d+|'[^']*'|"[^"]*");?/,
159→      );
160→      if (simpleMatch) {
161→        const value = simpleMatch[1];
162→        const basename = cleanId
163→          .replace(/^.*\//, '')
164→          .replace(/\.(web|native)?\.js$/, '');
165→        const namedExport =
166→          basename && /^[a-zA-Z_$]/.test(basename)
167→            ? `export const ${basename} = ${value};\n`
168→            : '';
169→        return code
170→          .replace(/["']use strict["'];?\s*/, '')
171→          .replace(
172→            simpleMatch[0],
173→            `${namedExport}export default ${value};`,
174→          );
175→      }
176→    },
177→  };
178→}
