import React, { useCallback, useEffect, useRef, useState } from 'react';
import { addons } from 'storybook/internal/manager-api';
import { useStorybookState } from 'storybook/internal/manager-api';
import { EVENTS } from './constants';
import { useIndexedDB } from './useIndexedDB';

function idbKeyFor(storyId: string) {
  return `sdui-json-${storyId}`;
}

function getChannel() {
  try { return addons.getChannel(); } catch { return null; }
}

export function JsonEditorPanel() {
  const state = useStorybookState();
  const storyId = state.storyId ?? '';

  const [defaultJson, setDefaultJson] = useState<string>('');
  const [text, setText] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [dirty, setDirty] = useState(false);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));

  useEffect(() => {
    const channel = getChannel();
    if (!channel) return;

    const onSetDefault = (json: string) => setDefaultJson(json);
    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
    channel.emit(EVENTS.REQUEST_DEFAULT);

    return () => { channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault); };
  }, [storyId]);

  useEffect(() => {
    if (!ready || !defaultJson) return;
    const initial = stored ?? defaultJson;
    setText(initial);
    setDirty(!!stored);
    setError(null);
  }, [ready, stored, defaultJson, storyId]);

  const handleChange = useCallback(
    (value: string) => {
      setText(value);
      setError(null);

      if (debounceRef.current) clearTimeout(debounceRef.current);

      debounceRef.current = setTimeout(() => {
        try {
          const parsed = JSON.parse(value);
          save(value);
          setDirty(true);
          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
        } catch (e) {
          setError((e as Error).message);
        }
      }, 400);
    },
    [save],
  );

  const handleReset = useCallback(() => {
    remove();
    setText(defaultJson);
    setDirty(false);
    setError(null);
    try {
      getChannel()?.emit(EVENTS.UPDATE_JSON, JSON.parse(defaultJson));
    } catch { /* noop */ }
  }, [defaultJson, remove]);

  const handleFormat = useCallback(() => {
    try {
      const parsed = JSON.parse(text);
      const formatted = JSON.stringify(parsed, null, 2);
      setText(formatted);
      save(formatted);
      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
      setError(null);
    } catch (e) {
      setError((e as Error).message);
    }
  }, [text, save]);

  if (!storyId) {
    return <div style={styles.empty}>Select a story to edit its JSON.</div>;
  }

  return (
    <div style={styles.container}>
      <div style={styles.toolbar}>
        <span style={styles.label}>
          SDUI JSON {dirty && <span style={styles.badge}>edited</span>}
        </span>
        <div style={styles.actions}>
          <button style={styles.btn} onClick={handleFormat}>
            Format
          </button>
          <button
            style={{ ...styles.btn, ...styles.btnReset }}
            onClick={handleReset}
            disabled={!dirty}
          >
            Reset
          </button>
        </div>
      </div>

      {error && <div style={styles.error}>JSON Error: {error}</div>}

      <textarea
        style={styles.textarea}
        value={text}
        onChange={e => handleChange(e.target.value)}
        spellCheck={false}
      />
    </div>
  );
}

const styles: Record<string, React.CSSProperties> = {
  container: {
    display: 'flex',
